INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (5, 1, 'This is a beautifull home away from home......', '1200.00', 4, 5, 3, 1, 'available', NULL, 1, 25, 513, 'Luxury Apartment', 'Ikoyi, Lagos', NULL, 'Shortlet');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (6, 1, 'This is one of the best luxurious home, that speak home away from home....!!!', '270000.00', 2, 1, 2, 1, 'available', NULL, 7, 25, 514, 'Beach Resort', 'Wine birds road, Eleko', NULL, 'Vacation Rental');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (7, 8, 'Escape to Twerk Resort & Vacation Place, where comfort, relaxation, and unforgettable experiences converge. Whether you\'re planning a romantic getaway, a family vacation, a business retreat, or a weekend escape, our resort offers the ideal destination to unwind and create lasting memories.', '200000.00', 4, 2, 2, 1, 'available', '95440bfddf8944139fc04de5bc165bb7.jpg', 7, 9, 182, 'Twerk Beach Resort', 'Twerk Crescent, Obudu', 'Obudu', 'Apartment');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (8, 8, 'Experience comfort, style, and convenience in this beautifully furnished 2-bedroom apartment located in the heart of Lekki. Designed for both short and extended stays, the apartment offers a relaxing atmosphere perfect for business travelers, couples, families, and vacationers.', '10.00', 4, 2, 2, 1, 'available', '36e880a48719427cbb441a0e8ee93004.jpg', 2, 25, 513, 'Luxury 2 Bed Apartment', '34, Admiraty way, Lekki Phase 1', 'Lagos', 'Apartment');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (9, 8, 'Guests can enjoy premium amenities, including 24-hour electricity, air conditioning, secure parking, CCTV surveillance, professional housekeeping, and round-the-clock security for a safe and comfortable stay.', '20000.00', 4, 2, 3, 1, 'available', '801f49bc7b4d4e988ea6b1efe02e4b33.jpg', 9, 15, 279, 'Luxury Apartment', '209, Abayomi Crescent, Kuje', 'Abuja', 'Apartment');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (10, 1, 'This is one of the best luxury resort on an island in the heart of africa', '15000.00', 2, 2, 3, 1, 'available', NULL, 15, 25, 513, 'Luxury Resort', 'Babara close, Ikoyi, Lagos', 'Lagos', 'Shortlet');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (11, 1, 'A shortlet apartment is a fully furnished, self-contained living space rented for flexible, short durations ranging from days to a few months. It provides the comfort and privacy of a home with amenities like 24/7 power, security, and housekeeping, making it popular among travelers and relocating families.', '10000.00', 4, 2, 1, 1, 'available', NULL, 10, 15, 278, 'Beautiful and Cozy Apartment', '199, Apple Court, Gwagwalada', 'Abuja', 'Shortlet');
INSERT INTO `properties` (`prop_id`, `prop_userid`, `prop_description`, `price_per_night`, `max_guest`, `bedrooms`, `bathrooms`, `is_verified`, `prop_availability_status`, `prop_mainimage_url`, `prop_typeid`, `prop_stateid`, `prop_lgaid`, `prop_title`, `prop_address`, `prop_city`, `prop_category`) VALUES (12, 1, 'The is the best Duplex in town, home away from home', '10000.00', 5, 3, 0, 1, 'available', NULL, 11, 15, 279, 'Luxury Duplex', '409, Pineaple crescent, Kuje Abuja', 'Abuja', 'Shortlet');
